function i(t){const n=t/100;return n>=1e4?(n/1e4).toFixed(2)+"万":n.toFixed(2)}function g(t){const n=t.getFullYear(),r=String(t.getMonth()+1).padStart(2,"0"),a=String(t.getDate()).padStart(2,"0"),e=String(t.getHours()).padStart(2,"0"),o=String(t.getMinutes()).padStart(2,"0"),s=String(t.getSeconds()).padStart(2,"0");return`${n}${r}${a}${e}${o}${s}`}export{i as a,g as f};
